-- Generated by scripts/audit-sp12h-cleanup.mjs
-- Snapshot 20260403130319-4d2216b146ef
-- Safe soft-delete targets only. Remaining repair candidates require canonical title insert/update first.
with targets as (
  select chart_key, song_title, chart_type, reason, nullif(keep_song_title, '') as keep_song_title
  from jsonb_to_recordset(convert_from(decode('', 'base64'), 'utf8')::jsonb) as x(
    chart_key text,
    song_title text,
    chart_type text,
    reason text,
    keep_song_title text
  )
)
update public.chart_metadata as cm
set
  is_deleted = true,
  source = 'sp12h_cleanup_audit'
from targets
where cm.is_deleted = false
  and cm.chart_key = targets.chart_key;
